import {useEffect,useState} from "react";
import axios from "axios";
import {MapContainer,TileLayer,Popup,Circle,useMap} from "react-leaflet";
import "leaflet/dist/leaflet.css";

/* 🔽 ADDED: Modal Component (no UI changes to your layout) */
function Modal({submitResolve,setProofImage,close}){
  return(
    <div style={{
      position:"fixed",
      top:0,left:0,width:"100%",height:"100%",
      background:"rgba(0,0,0,0.7)",
      display:"flex",
      justifyContent:"center",
      alignItems:"center"
    }}>
      <div style={{background:"#142c4c",padding:20,borderRadius:10}}>
        <h3>Upload Proof</h3>

        <input
          type="file"
          accept="image/*"
          capture="environment"
          onChange={(e)=>setProofImage(e.target.files[0])}
        />

        <br/><br/>

        <button onClick={submitResolve}>Submit</button>
        <button onClick={close} style={{marginLeft:10}}>Cancel</button>
      </div>
    </div>
  )
}

function ChangeMapView({coords}){
  const map = useMap();

  useEffect(()=>{
    if(coords){
      map.setView(coords,15);
    }
  },[coords,map]);

  return null;
}

export default function HospitalDashboard(){

  const [alerts,setAlerts]=useState([]);
  const [loading,setLoading]=useState(true);
  const [error,setError]=useState("");
  const [selectedLocation,setSelectedLocation]=useState(null);
  const [pulse,setPulse]=useState(80);

  /* 🔽 ADDED STATES (NO UI CHANGE) */
  const [showModal,setShowModal]=useState(false);
  const [selectedAlertId,setSelectedAlertId]=useState(null);
  const [proofImage,setProofImage]=useState(null);

  const loadAlerts=()=>{
    axios.get("http://127.0.0.1:8000/api/hospital-alerts/")
      .then(res=>{
        setAlerts(res.data);
        setLoading(false);
      })
      .catch(()=>{
        setError("Failed to load alerts");
        setLoading(false);
      });
  }

  useEffect(()=>{ loadAlerts(); },[]);

  useEffect(()=>{
    const interval=setInterval(()=>{ loadAlerts(); },10000);
    return ()=>clearInterval(interval);
  },[]);

  useEffect(()=>{
    const interval=setInterval(()=>{
      setPulse(prev => prev===80 ? 140 : 80);
    },700);

    return ()=>clearInterval(interval);
  },[]);

  /* ❌ OLD FUNCTION REMOVED LOGIC ONLY */
  /* 🔽 REPLACED WITH MODAL TRIGGER */
  const resolveAlert=(id)=>{
    setSelectedAlertId(id);
    setShowModal(true);
  }

  /* 🔽 NEW VERIFY + SUBMIT FUNCTION */
  const submitResolve=()=>{
    if(!proofImage){
      alert("Upload proof");
      return;
    }

    navigator.geolocation.getCurrentPosition(pos=>{
      const formData=new FormData();
      formData.append("proof_image",proofImage);
      formData.append("latitude",pos.coords.latitude);
      formData.append("longitude",pos.coords.longitude);

      axios.post(
        `http://127.0.0.1:8000/api/resolve-api/${selectedAlertId}/`,
        formData
      )
      .then(()=>{
        alert("Resolved ✅");
        setShowModal(false);
        setProofImage(null);
        loadAlerts();
      })
      .catch(()=>alert("Verification failed ❌"));
    });
  }

  const active=alerts.filter(a=>a.status!=="resolved");
  const resolved=alerts.filter(a=>a.status==="resolved");

  const exportCSV=()=>{
    const rows=[
      ["Device","Latitude","Longitude","Message","Status","Time"],
      ...alerts.map(a=>[
        a.device_id,
        a.latitude,
        a.longitude,
        a.message,
        a.status,
        new Date(a.timestamp).toLocaleString()
      ])
    ]

    const csvContent=
      "data:text/csv;charset=utf-8,"+
      rows.map(e=>e.join(",")).join("\n")

    const encodedUri=encodeURI(csvContent);
    const link=document.createElement("a");

    link.setAttribute("href",encodedUri);
    link.setAttribute("download","hospital_alerts_report.csv");

    document.body.appendChild(link);
    link.click();
  }

  if(loading) return <div style={page}>Loading dashboard...</div>;
  if(error) return <div style={page}>{error}</div>;

  return(
    <div style={page}>

      <h1 style={{color:"#22c55e"}}>
        🏥 Hospital Emergency Dashboard
      </h1>

      <div style={statsContainer}>

        <div style={card}>
          <h3>Total Alerts</h3>
          <p style={number}>{alerts.length}</p>
        </div>

        <div style={card}>
          <h3>Active Alerts</h3>
          <p style={{...number,color:"#ef4444"}}>{active.length}</p>
        </div>

        <div style={card}>
          <h3>Resolved Alerts</h3>
          <p style={{...number,color:"#22c55e"}}>{resolved.length}</p>
        </div>

        <button style={exportBtn} onClick={exportCSV}>
          Export Report
        </button>

      </div>

      <MapContainer
        center={[17.38,78.48]}
        zoom={11}
        style={{height:350,marginTop:20,borderRadius:12}}
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>

        <ChangeMapView coords={selectedLocation}/>

        {active.map(a=>(
          a.latitude && a.longitude && (
            <Circle
              key={a.id}
              center={[a.latitude,a.longitude]}
              radius={pulse}
              pathOptions={{
                color:"red",
                fillColor:"red",
                fillOpacity:0.5
              }}
            >
              <Popup>
                <strong>{a.message}</strong><br/>
                Status: {a.status}
              </Popup>
            </Circle>
          )
        ))}

        {selectedLocation && (
          <Circle
            center={selectedLocation}
            radius={pulse}
            pathOptions={{
              color:"#f97316",
              fillColor:"#f97316",
              fillOpacity:0.5
            }}
          >
            <Popup>Selected Alert</Popup>
          </Circle>
        )}

      </MapContainer>

      <h2 style={{marginTop:30}}>Active Alerts</h2>
      <Table alerts={active} resolveAlert={resolveAlert} setSelectedLocation={setSelectedLocation}/>

      <h2 style={{marginTop:30}}>Resolved Alerts History</h2>
      <Table alerts={resolved} setSelectedLocation={setSelectedLocation}/>

      {/* 🔽 ADDED MODAL (NO UI CHANGE TO MAIN PAGE) */}
      {showModal && (
        <Modal
          submitResolve={submitResolve}
          setProofImage={setProofImage}
          close={()=>setShowModal(false)}
        />
      )}

    </div>
  )
}
